// Car 1: Road 1 (Y=500) - Moves RIGHT at 3 px/frame
export function onUpdate(entity: Entity, dt: number) {
  // Move right by speed amount
  entity.transform.x += speed;

  // Wrap around screen edges
  if (entity.transform.x > maxX) {
    entity.transform.x = minX;
  }
}

// Exported variables for tuning
export const speed = 3;
export const minX = -50;
export const maxX = 850;

